import { describe, it, expect } from 'vitest'
import { SubmitRetryableMessageDataParser } from '../../src/message/messageDataParser'

describe('SubmitRetryableMessageDataParser', () => {
  it('parses l1 to l2 message (retryable with calldata)', () => {
    const parser = new SubmitRetryableMessageDataParser()
    // Taken from https://etherscan.io/tx/0x83636bc9e73b4065d1e5d69b52e43ec05a9430a0cb270c8f595ac22399fe3c20#eventlog
    const retryableData =
      ''

    const res = parser.parse(retryableData)

    expect(res.callValueRefundAddress).toBe(
      '0x7F869dC59A96e798e759030b3c39398ba584F087'
    )
    expect(res.data).toBe(
      ''
    )
    expect(res.destAddress).toBe('0x467194771dAe2967Aef3ECbEDD3Bf9a310C76C65')
    expect(res.excessFeeRefundAddress).toBe(
      '0x7F869dC59A96e798e759030b3c39398ba584F087'
    )
    expect(res.gasLimit).toBe(0x0210f1n)
    expect(res.l1Value).toBe(0x30346f1c785en)
    expect(res.l2CallValue).toBe(0n)
    expect(res.maxFeePerGas).toBe(0x172c5865n)
    expect(res.maxSubmissionFee).toBe(0x53280cf149n)
  })

  it('parses eth deposit in an l1 to l2 message', () => {
    const parser = new SubmitRetryableMessageDataParser()
    // Taken from https://etherscan.io/tx/0xfe54a8166c62cf65468234c728249c28997904d6988913625ca5c4e249d06058#eventlog
    const retryableData =
      ''

    const res = parser.parse(retryableData)

    expect(res.callValueRefundAddress).toBe(
      '0xf71946496600e1e1d47b8A77EB2f109Fd82dc86a'
    )
    expect(res.data).toBe('0x')
    expect(res.destAddress).toBe('0xf71946496600e1e1d47b8A77EB2f109Fd82dc86a')
    expect(res.excessFeeRefundAddress).toBe(
      '0xf71946496600e1e1d47b8A77EB2f109Fd82dc86a'
    )
    expect(res.gasLimit).toBe(0n)
    // 30.01 ETH = 30010000000000000000n
    expect(res.l1Value).toBe(30010000000000000000n)
    expect(res.l2CallValue).toBe(0n)
    expect(res.maxFeePerGas).toBe(0n)
    expect(res.maxSubmissionFee).toBe(0x370e285a0cn)
  })
})
